<div style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;">[[File:Different devices.svg|75px|left]]<This template is adaptive displays differently in '''mobile''' and '''desktop''' view. Read the documentation for an explanation of the differences and why they exist.</div><noinclude>{{Documentation}}</noinclude>
<big>Big text</big>

{{#ifeq: {{{1}}} | adaptive 
 |<table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:71px;padding:3px;">[[File:Different devices simple.svg|65x65px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template is [[Adaptive web design|adaptive]] and <strong>displays differently in mobile and desktop view</strong>. Read the documentation for an explanation of the differences and why they exist.</span></td></tr></table> 
 |{{#ifeq: {{{1}}} | nomobile
  |<table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:55px">[[File:Handheld devices no.svg|55px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template does not display in the mobile view of Wikipedia; it is <strong>desktop only</strong>. Read the documentation for an explanation.</span></td></tr></table>
  |{{#ifeq: {{{1}}} | nodesktop 
   |<table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:55px">[[File:Desktop devices no.svg|55px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template does not display in the desktop view of Wikipedia; it is <strong>mobile only</strong>. Read the documentation for an explanation.</span></td></tr></table>
  }}
 }}
}}<noinclude>
{{Documentation}}
</noinclude>

{{#switch:{{{1}}}
 | adaptive = <table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:71px;padding:3px;">[[File:Different devices simple.svg|65x65px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template is [[Adaptive web design|adaptive]] and <strong>displays differently in mobile and desktop view</strong>. Read the documentation for an explanation of the differences and why they exist.</span></td></tr></table>
 | nomobile = <table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:55px">[[File:Handheld devices no.svg|55px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template does not display in the mobile view of Wikipedia; it is <strong>desktop only</strong>. Read the documentation for an explanation.</span></td></tr></table>
 | nodesktop = <table class="plainlinks advert" role="presentation" style="margin: 0 10%; border: 1px solid #aaa; border-left: 10px solid #1e90ff; background: #fbfbfb;"><tr><td class="mbox-image" style="width:55px">[[File:Desktop devices no.svg|55px|link=|alt=]]</td><td class="mbox-text"><span class="mbox-text-span">This template does not display in the desktop view of Wikipedia; it is <strong>mobile only</strong>. Read the documentation for an explanation.</span></td></tr></table>
}}<noinclude>
